+    unsafe { frankenlibc_abi::grp_abi::endgrent() };
+
+    let errors = Arc::new(AtomicUsize::new(0));
+    let path_for_writer = path.clone();
+    let writer = std::thread::spawn(move || {
+        for i in 0..200 {
